#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/*
 * Direct-Mapped Cache Simulator
 * Demonstrates: Cache hit/miss, direct mapping, block transfer,
 * temporal and spatial locality, write policies
 */

#define CACHE_SIZE 16 /* Number of cache lines */
#define BLOCK_SIZE 4 /* Bytes per block */
#define MEMORY_SIZE 256 /* Simulated main memory size */

/* Cache line structure */
typedef struct {
 int valid; /* 1 if line contains valid data */
 int dirty; /* 1 if data modified (write-back) */
 int tag; /* Tag bits */
 int index; /* Index bits */
 unsigned char data[BLOCK_SIZE]; /* Stored data block */
 int last_access; /* For LRU tracking (if we add associativity) */
} CacheLine;

/* Statistics structure */
typedef struct {
 int hits;
 int misses;
 int read_hits;
 int write_hits;
 int read_misses;
 int write_misses;
 int memory_accesses; /* Count of actual main memory accesses */
} CacheStats;

/* Cache and memory */
CacheLine cache[CACHE_SIZE];
unsigned char memory[MEMORY_SIZE];
CacheStats stats;

/* Write policy: 1 = write-through, 0 = write-back */
int write_policy = 0; /* Using write-back */

/* Initialize cache and memory */
void initialize_system() {
 int i, j;

 /* Initialize cache */
 for (i = 0; i < CACHE_SIZE; i++) {
 cache[i].valid = 0;
 cache[i].dirty = 0;
 cache[i].tag = -1;
 cache[i].index = i;
 cache[i].last_access = 0;
 for (j = 0; j < BLOCK_SIZE; j++) {
 cache[i].data[j] = 0;
 }
 }

 /* Initialize main memory with test pattern */
 for (i = 0; i < MEMORY_SIZE; i++) {
 memory[i] = (unsigned char)(i % 256);
 }

 /* Initialize statistics */
 memset(&stats, 0, sizeof(CacheStats));

 printf("System initialized: Cache=%d lines, Block=%d bytes, Memory=%d bytes\n",
 CACHE_SIZE, BLOCK_SIZE, MEMORY_SIZE);
}

/* Calculate index and tag from address */
void decode_address(int address, int *index, int *tag, int *offset) {
 /* Index bits: log2(CACHE_SIZE) */
 int index_bits = 0;
 int temp = CACHE_SIZE;
 while (temp > 1) {
 temp >>= 1;
 index_bits++;
 }

 /* Offset bits: log2(BLOCK_SIZE) */
 int offset_bits = 0;
 temp = BLOCK_SIZE;
 while (temp > 1) {
 temp >>= 1;
 offset_bits++;
 }

 *offset = address & ((1 << offset_bits) - 1);
 *index = (address >> offset_bits) & ((1 << index_bits) - 1);
 *tag = address >> (index_bits + offset_bits);
}

/* Read from cache system */
unsigned char cache_read(int address) {
 int index, tag, offset;

 decode_address(address, &index, &tag, &offset);

 /* Check if data is in cache */
 if (cache[index].valid && cache[index].tag == tag) {
 /* Cache Hit! */
 stats.hits++;
 stats.read_hits++;
 cache[index].last_access = 0; /* Update LRU counter */

 /* Increment LRU counters for other lines */
 for (int i = 0; i < CACHE_SIZE; i++) {
 if (i != index) cache[i].last_access++;
 }

 printf("READ HIT: Addr=0x%02X, Index=%d, Offset=%d, Data=%d\n",
 address, index, offset, cache[index].data[offset]);
 return cache[index].data[offset];
 }

 /* Cache Miss - fetch from memory */
 stats.misses++;
 stats.read_misses++;
 stats.memory_accesses++;

 printf("READ MISS: Addr=0x%02X, Index=%d - Loading block from memory\n",
 address, index);

 /* Load entire block (spatial locality) */
 int block_start = address - offset; /* Block-aligned address */
 for (int i = 0; i < BLOCK_SIZE; i++) {
 cache[index].data[i] = memory[block_start + i];
 }

 /* Update cache line metadata */
 cache[index].valid = 1;
 cache[index].dirty = 0;
 cache[index].tag = tag;
 cache[index].last_access = 0;

 return cache[index].data[offset];
}

/* Write to cache system */
void cache_write(int address, unsigned char value) {
 int index, tag, offset;

 decode_address(address, &index, &tag, &offset);

 /* Check if block is in cache */
 if (cache[index].valid && cache[index].tag == tag) {
 /* Write hit */
 stats.hits++;
 stats.write_hits++;

 if (write_policy) {
 /* Write-through: update both cache and memory */
 cache[index].data[offset] = value;
 memory[address] = value;
 printf("WRITE HIT (Write-through): Addr=0x%02X, Value=%d\n",
 address, value);
 } else {
 /* Write-back: only update cache, mark dirty */
 cache[index].data[offset] = value;
 cache[index].dirty = 1;
 printf("WRITE HIT (Write-back): Addr=0x%02X, Value=%d (marked dirty)\n",
 address, value);
 }
 } else {
 /* Write miss */
 stats.misses++;
 stats.write_misses++;
 stats.memory_accesses++;

 printf("WRITE MISS: Addr=0x%02X, Index=%d - Loading block first\n",
 address, index);

 /* Load block on write-miss (write-allocate) */
 int block_start = address - offset;
 for (int i = 0; i < BLOCK_SIZE; i++) {
 cache[index].data[i] = memory[block_start + i];
 }

 cache[index].valid = 1;
 cache[index].tag = tag;

 if (write_policy) {
 cache[index].data[offset] = value;
 memory[address] = value;
 } else {
 cache[index].data[offset] = value;
 cache[index].dirty = 1;
 }
 }
}

/* Display cache state */
void display_cache() {
 printf("\n=== CACHE STATE ===\n");
 printf("Idx Valid Dirty Tag Data (first byte)\n");
 printf("--- ----- ----- ---- -----------------\n");

 for (int i = 0; i < CACHE_SIZE; i++) {
 if (cache[i].valid) {
 printf("%3d %d %d %2d %d\n",
 i, cache[i].valid, cache[i].dirty, 
 cache[i].tag, cache[i].data[0]);
 }
 }
 printf("===================\n\n");
}

/* Print performance statistics */
void print_statistics() {
 int total_accesses = stats.hits + stats.misses;
 float hit_ratio = (float)stats.hits / total_accesses * 100.0f;

 printf("\n===================\n");
 printf("CACHE STATISTICS\n");
 printf("===================\n");
 printf("Total Accesses: %d\n", total_accesses);
 printf("Total Hits: %d\n", stats.hits);
 printf("Total Misses: %d\n", stats.misses);
 printf("Hit Ratio: %.2f%%\n", hit_ratio);
 printf("\nRead Hits: %d\n", stats.read_hits);
 printf("Read Misses: %d\n", stats.read_misses);
 printf("Write Hits: %d\n", stats.write_hits);
 printf("Write Misses: %d\n", stats.write_misses);
 printf("Memory Accesses: %d\n", stats.memory_accesses);
 printf("===================\n");
}

int main() {
 printf("========================================\n");
 printf("DIRECT-MAPPED CACHE SIMULATOR\n");
 printf("========================================\n");

 initialize_system();

 /* DEMONSTRATION 1: Temporal Locality */
 printf("\n--- DEMO 1: TEMPORAL LOCALITY ---\n");
 printf("Accessing same address multiple times:\n");
 int addr = 0x50;
 for (int i = 0; i < 5; i++) {
 cache_read(addr);
 }

 /* DEMONSTRATION 2: Spatial Locality */
 printf("\n--- DEMO 2: SPATIAL LOCALITY ---\n");
 printf("Accessing consecutive addresses (block size = %d):\n", BLOCK_SIZE);
 for (int i = 0; i < 8; i++) {
 cache_read(0x10 + i); /* Addresses in same block */
 }

 /* DEMONSTRATION 3: Write Policy */
 printf("\n--- DEMO 3: WRITE OPERATIONS ---\n");
 write_policy = 1; /* Write-through */
 printf("Using Write-Through policy:\n");
 cache_write(0x80, 100);
 cache_write(0x80, 200); /* Same address - temporal locality */

 display_cache();

 print_statistics();

 return 0;
}
